module top_module (
    input g,
    input c,
    input l,
    input e,
    output reg ff
);
    always @(*) begin
        case ({g, c, l, e})
            4'b0111: ff = 1'b0;
            4'b0101: ff = 1'b1;
            4'b1110: ff = 1'b1;
            4'b1100: ff = 1'b1;
            4'b0010: ff = 1'b1;
            4'b0011: ff = 1'b1;
            4'b0000: ff = 1'b1;
            4'b1001: ff = 1'b1;
            4'b0001: ff = 1'b1;
            4'b0110: ff = 1'b1;
            4'b1111: ff = 1'b0;
            4'b1011: ff = 1'b1;
            4'b1010: ff = 1'b0;
            4'b0100: ff = 1'b1;
            4'b1101: ff = 1'b0;
            4'b1000: ff = 1'b0;
        endcase
    end
endmodule
